// Collapse all Job_ID rows into a single array and pass forward
const existingIds = $input.all()
  .map(r => String(r.json['Job_ID'] || r.json['job_id'] || Object.values(r.json)[0] || '').trim())
  .filter(Boolean);

return [{ json: { existingIds } }];

/*
 ╔══════════════════════════════════════════════════════════════╗
 ║     🔬 SMART FILTER + DUPLICATE CHECKER (all-in-one)        ║
 ║                                                              ║
 ║  FILTER RULES:                                               ║
 ║    ✅ Must have Java + Spring Boot in title/desc/skills      ║
 ║    ✅ Experience lower bound must be ≤ 6 yrs                 ║
 ║       "1-6 yrs" ✅  "3-8 yrs" ✅  "7+ yrs" ❌              ║
 ║    ❌ Exclude titles: Staff, Principal, Fellow,              ║
 ║                       Director, VP, Manager                  ║
 ║    ❌ Exclude: GC, Green Card, Security Clearance,           ║
 ║               TS/SCI, Top Secret, US Citizen required        ║
 ║                                                              ║
 ║  DUPLICATE CHECK:                                            ║
 ║    ❌ Skip if Job_ID already in Google Sheet                 ║
 ║    ❌ Skip if Job_ID seen earlier in this same batch         ║
 ╚══════════════════════════════════════════════════════════════╝
*/

// $input has the JSearch API response.
// existingIds came from '📦 Collect Existing IDs' — still accessible via $('...')
// since it ran before this node in a straight sequential chain.
// const jobs = $input.first().json.data.flatMap(item => item.data || []);

const jobs = ($input.first().json.data || []).flat();

const existingIds = new Set(
  $('📦 Collect Existing IDs1').first().json.existingIds || []
);

if (!jobs.length) {
  return [{ json: {
    unique_jobs: [], filtered_jobs: [],
    passed_count: 0, filtered_count: 0, total_fetched: 0, __empty: true
  }}];
}

// ─── Patterns ───────────────────────────────────────────────────
const EXCL_TITLES = [
  /\bstaff\b/i, /\bprincipal\b/i, /\bfellow\b/i,
  /\bdirector\b/i, /\bvp\b/i, /\bvice\s+president/i,
  /\bmanager\b/i, /\blead\s+engineer/i
];
const EXCL_CLEARANCE_KEYWORDS = [
  "green card",
  "gc required",
  "security clearance",
  "clearance required",
  "clearance needed",
  "active clearance",
  "must be a us citizen",
  "must be us citizen",
  "us citizenship required",
  "ts/sci",
  "ts-sci",
  "secret",
  "secret clearance",
  "top secret",
  "dod clearance",
  "gc holder",
  "polygraph",
  "require gc",
  "must hold clearance"
];
// ────────────────────────────────────────────────────────────────

const uniqueJobs   = [];
const filteredJobs = [];
const seenBatch    = new Set();

for (const job of jobs) {
  const title      = (job.job_title || '').trim();
  const desc       = (job.job_description || '').trim();
  const skills     = (job.job_required_skills || []).join(' ');
  const searchable = `${title} ${desc} ${skills}`.toLowerCase();
  const jobId      = job.job_id || '';
  let   rejectReason = null;

  // 1 — Must have Java AND Spring Boot
  const hasJava       = /\bjava\b/i.test(searchable);
  const hasSpringBoot = /spring[\s\-]*boot|springboot/i.test(searchable);
  if (!hasJava ) {  //|| !hasSpringBoot
    rejectReason = `Missing tech — java:${hasJava} springBoot:${hasSpringBoot}`;
  }

  // 2 — Exclude senior titles
  if (!rejectReason) {
    for (const p of EXCL_TITLES) {
      if (p.test(title)) { rejectReason = `Excluded title: "${title}"`; break; }
    }
  }

  // 3 — Exclude clearance/GC
  if (!rejectReason) {
    const matchedKeyword = EXCL_CLEARANCE_KEYWORDS.find(kw =>      searchable.includes(kw));
    if (matchedKeyword) {
      rejectReason = `Clearance/GC required (${matchedKeyword})`;
    }
}

  // 4 — Experience: lower bound must be ≤ 6
  if (!rejectReason) {
    let minYears = null;
    const expMonths = job.job_required_experience?.required_experience_in_months;
    if (expMonths != null) minYears = expMonths / 12;

    if (minYears === null) {
      const rm = desc.match(/(\d+)\s*(?:to|[-–])\s*(\d+)\s*\+?\s*years?/i);
      if (rm) {
        minYears = parseInt(rm[1], 10);
      } else {
        const sm = desc.match(/(?:minimum|at least|over|\b)(\d+)\+?\s*years?\s*(?:of\s*)?(?:experience|exp)/i);
        if (sm) minYears = parseInt(sm[1], 10);
      }
    }
    if (minYears !== null && minYears > 6) {
      rejectReason = `Exp min too high: ${minYears.toFixed(1)} yrs (must start ≤6)`;
    }
  }

  // 5 — Duplicate check
  if (!rejectReason) {
    if (existingIds.has(jobId) || seenBatch.has(jobId)) {
      rejectReason = `Duplicate — Job_ID already in sheet`;
    } else {
      seenBatch.add(jobId);
    }
  }

  const url = job.job_apply_link || '';
  // Route result
  if (rejectReason) {
    filteredJobs.push({job_url : url ? `=HYPERLINK("${url}","${title.replace(/"/g, '""')}")` : '', job_id: jobId, title, company: job.employer_name || '', reject_reason: rejectReason });
  } else {
    // Map to sheet schema
    let postedAge = 'Unknown';
    if (job.job_posted_at_datetime_utc) {
      const diffMs = Date.now() - new Date(job.job_posted_at_datetime_utc).getTime();
      const h = Math.floor(diffMs / 3600000), d = Math.floor(h / 24);
      postedAge = d > 0 ? `${d}d ago` : h > 0 ? `${h}h ago` : 'Just now';
    }

    let pub = job.job_publisher || '';
    if (!pub) {
      if      (url.includes('linkedin'))     pub = 'LinkedIn';
      else if (url.includes('ziprecruiter')) pub = 'ZipRecruiter';
      else if (url.includes('indeed'))       pub = 'Indeed';
      else if (url.includes('glassdoor'))    pub = 'Glassdoor';
      else if (url.includes('lever'))        pub = 'Lever';
      else if (url.includes('greenhouse'))   pub = 'Greenhouse';
      else if (url.includes('workday'))      pub = 'Workday';
      else                                   pub = 'Direct';
    }
    const em = job.job_required_experience?.required_experience_in_months;
    const expLabel = em ? ` | Exp: ~${(em/12).toFixed(0)} yrs` : '';

    uniqueJobs.push({
      Job_ID:         jobId,
      Publisher:      pub,
      Company:        job.employer_name || '',
      Raw_URL:        url,
      Job_URL:        url ? `=HYPERLINK("${url}","${title.replace(/"/g, '""')}")` : '',
      Location:       [job.job_city, job.job_state].filter(Boolean).join(', ') + (job.job_is_remote ? ' (Remote)' : ''),
      Posted_Age:     postedAge,
     Posted_At: (() => {
  const d = job.job_posted_at_datetime_utc ? new Date(job.job_posted_at_datetime_utc) : new Date();
  return d.toLocaleString('en-US', { timeZone: 'America/New_York', month: '2-digit', day: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit', hour12: true });
})(),
      Last_Checked:   new Date().toISOString(),
      Notes:          `Imported from JSearch${expLabel}`,
      Position:       title,
      Priority:       'Medium',
      Application_ID: '',
      Status:         'Not Applied',
      Job_Desc:  job.job_description,
      // Add this one field to every uniqueJobs.push()
Resume_Profile: JSON.stringify($getWorkflowStaticData('global').resumeProfile)
    });
  }
}

console.log(`Total: ${jobs.length} | Passed: ${uniqueJobs.length} | Rejected: ${filteredJobs.length}`);

return [{ json: {
  unique_jobs:    uniqueJobs,
  filtered_jobs:  filteredJobs,
  passed_count:   uniqueJobs.length,
  filtered_count: filteredJobs.length,
  total_fetched:  jobs.length
}}];

const job = $('📝 Split Jobs into Rows').item.json;
const raw = $json.output?.[0]?.content?.[0]?.text || '';

let ats = {};
try {
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  ats = JSON.parse(cleaned);
} catch (e) {
  ats = {
    fitScore: 0,
    confidence: 0,
    decision: 'parse_error',
    hardFlags: ['parse_error'],
    seniorityMismatch: false,
    matchedStrengths: [],
    missingMustHaves: [],
    scoreJustification: `Parse failed: ${e.message}`,
    coverLetter: ''
  };
}

// Clean hyperlink formula
let rawUrl = job.Job_URL || '';
const urlMatch = rawUrl.match(/=HYPERLINK\("(https?:\/\/[^"]+)"/);
if (urlMatch) rawUrl = urlMatch[1];

// Helper functions
function parseFlags(raw) {
  if (!raw) return [];
  return String(raw).split(',').map(f => f.trim()).filter(Boolean).map(f => {
    if (f === 'senior_title')    return 'Senior Title';
    if (f.includes('6plus'))     return '6+ Years Required';
    if (f.includes('clearance')) return 'Clearance / Citizenship';
    return f;
  });
}
function getState(loc) {
  if (!loc) return '';
  if (/remote/i.test(loc) && !String(loc).includes(',')) return 'Remote';
  const m = String(loc).match(/,\s*([A-Za-z][A-Za-z\s]{1,18})(?:\s*\(|$)/);
  return m ? m[1].trim() : '';
}
function extractUrl(raw) {
  if (!raw) return '';
  const m = String(raw).match(/https?:\/\/[^\s"]+/);
  return m ? m[0] : '';
}

function parseDate(val) {
  if (!val) return null;
  const s = String(val).trim();
  // Handle "MM/DD/YYYY, H:MM AM/PM" — Google Sheets locale format
  const fmts = [
    { r: /^(\d{1,2})\/(\d{1,2})\/(\d{4}),?\s*(\d{1,2}):(\d{2})\s*(AM|PM)$/i,
      fn: (mm,dd,yyyy,hh,min,ap) => {
        let h = parseInt(hh);
        if (ap.toUpperCase() === 'PM' && h !== 12) h += 12;
        if (ap.toUpperCase() === 'AM' && h === 12) h = 0;
        return new Date(parseInt(yyyy), parseInt(mm)-1, parseInt(dd), h, parseInt(min)).toISOString();
      }
    }
  ];
  for (const {r, fn} of fmts) {
    const m = s.match(r);
    if (m) try { return fn(...m.slice(1)); } catch {}
  }
  // Fallback — ISO strings
  try {
    const d = new Date(s);
    if (!isNaN(d.getTime())) return d.toISOString();
  } catch {}
  return null;
}

const category = ats.decision === 'strong_match' ? 'strong'
               : ats.decision === 'maybe'         ? 'maybe'
               : ats.decision === 'weak'           ? 'weak'
               : ats.decision === 'no'             ? 'no'
               :                                    'no';

// Build dashboard job object for Gist (passed to next node)
const gistJob = (ats.decision && ats.decision !== 'parse_error' && job.Job_ID) ? {
  id:            String(job.Job_ID),
  category,
  company:       String(job.Company  || '').trim(),
  position:      String(job.Position || '').trim(),
  location:      String(job.Location || '').trim(),
  state:         getState(job.Location),
  url:           extractUrl(rawUrl || ''),
  score:         parseFloat(ats.fitScore) || 0,
  ats_resume:    String(job.ATS_Resume || ''),
  job_desc:      String(job.Job_Desc   || ''),
  tags:          (ats.matchedStrengths || []).join(' | ').split('|').map(s => s.trim()).filter(Boolean).slice(0, 6),
  missing_tags:  (ats.missingMustHaves || []).join(' | ').split('|').map(s => s.trim()).filter(Boolean).slice(0, 4),
  flags:         parseFlags((ats.flags || []).join(', ')),
  justification: String(ats.scoreJustification || ''),
  cover:         String(ats.coverLetter        || ''),
  posted_dt:     parseDate(job.Posted_At),
  publisher:     String(job.Publisher || '').trim(),
} : null;

return {
  json: {
    // ── Sheet columns (unchanged) ──
    Job_ID:             job.Job_ID,
    Publisher:          job.Publisher,
    Company:            job.Company,
    Position:           job.Position,
    Job_URL:            job.Job_URL,
    Description:        job.Job_Desc,
    Location:           job.Location,
    Last_Checked:       job.Last_Checked,
    Posted_Age:         job.Posted_Age,
    'Posted At':        job.Posted_At,
    FitScore:           ats.fitScore    ?? 0,
    Decision:           ats.decision    ?? '',
    Confidence:         ats.confidence  ?? 0,
    Hard_Flags:         (ats.flags            || []).join(', '),
    Strengths:          (ats.matchedStrengths || []).join(' | '),
    Missings:           (ats.missingMustHaves || []).join(' | '),
    SeniorityMismatch:  ats.seniorityMismatch ? 'Yes' : 'No',
    ScoreJustification: ats.scoreJustification ?? '',
    CoverLetter:        ats.coverLetter        ?? '',
    // ── Gist job object (passed to next node) ──
    _gistJob: gistJob ? JSON.stringify(gistJob) : null
  }
};


